// Normalize and validate incoming payload from VISAI backend
const body = $input.first().json.body || $input.first().json;

const email = (body.email || '').trim().toLowerCase();
const analysisId = body.analysis_id || body.analysisId || '';
const createdAt = body.created_at || body.createdAt || new Date().toISOString();
const resultUrl = body.result_url || body.resultUrl || `https://visaiapp.com/result/${analysisId}`;
const captureUrl = body.capture_url || body.captureUrl || '';
const unsubscribeUrl = body.unsubscribe_url || body.unsubscribeUrl || `https://visaiapp.com/unsubscribe?email=${encodeURIComponent(email)}`;
const marketingConsent = body.marketing_consent === true || body.marketing_consent === 'true' || body.marketingConsent === true;

if (!email) throw new Error('Missing required field: email');
if (!analysisId) throw new Error('Missing required field: analysis_id');

return [{
  json: {
    email,
    analysis_id: analysisId,
    created_at: createdAt,
    result_url: resultUrl,
    capture_url: captureUrl,
    unsubscribe_url: unsubscribeUrl,
    marketing_consent: marketingConsent
  }
}];

